class BookMyShow {
public:
    BookMyShow(int n, int m) : n(n), m(m), available_seats(n, m), first_available_seat(n, 0) {}

    vector<int> gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; ++i) {
            if (available_seats[i] >= k) {
                int start = first_available_seat[i];
                if (m - start >= k) {
                    available_seats[i] -= k;
                    first_available_seat[i] += k;
                    return {i, start};
                }
            }
        }
        return {};
    }

    bool scatter(int k, int maxRow) {
        int total_available = 0;
        for (int i = 0; i <= maxRow; ++i) {
            total_available += available_seats[i];
        }
        if (total_available < k) return false;

        for (int i = 0; i <= maxRow; ++i) {
            int seats_to_allocate = min(k, available_seats[i]);
            available_seats[i] -= seats_to_allocate;
            k -= seats_to_allocate;
            while (seats_to_allocate > 0) {
                int seats_to_end = min(seats_to_allocate, m - first_available_seat[i]);
                first_available_seat[i] += seats_to_end;
                seats_to_allocate -= seats_to_end;
            }
            if (k == 0) break;
        }
        return true;
    }

private:
    int n, m;
    vector<int> available_seats;
    vector<int> first_available_seat;
};

